class Product { final String id, code, name, category; final double price; final bool available; Product({required this.id, required this.code, required this.name, required this.category, required this.price, this.available = true}); factory Product.fromJson(Map<String, dynamic> j) => Product(id: j['id'], code: j['code'], name: j['name'], category: j['category'], price: (j['price'] as num).toDouble(), available: j['available'] ?? true); }
